mapper.insert:
insert into user_anime (
    user_id, anime_id, watch_status, current_episode, score, is_favorite,
    start_date, finish_date, last_watch_time, remark
) values (
    #{userId}, #{animeId}, #{watchStatus}, #{currentEpisode}, #{score}, #{isFavorite},
    #{startDate}, #{finishDate}, #{lastWatchTime}, #{remark}
)

mapper.select:
select ua.id, ua.anime_id, a.name as anime_name, a.cover_url, a.total_episodes, a.type, ua.watch_status, ua.current_episode, ua.score, ua.is_favorite, ua.start_date, ua.finish_date, ua.last_watch_time, ua.remark from user_anime ua left join anime a on ua.anime_id = a.id
ua.user_id = #{userId}
and ua.watch_status = #{watchStatus}
and a.name like concat('%', #{keyword}, '%')
order by ua.updated_at desc, ua.id desc
